"use strict";(globalThis.webpackChunkbezimienny_111_github_io=globalThis.webpackChunkbezimienny_111_github_io||[]).push([[8435],{7733(a){a.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"pluginy-union","metadata":{"permalink":"/newsy/pluginy-union","source":"@site/newsy/2026-04-03-pluginy-union.md","title":"Najbardziej cziter\u2026 tzn. u\u017cyteczne pluginy pod Uniona","description":"Dzi\u015b chcia\u0142bym zaprosi\u0107 Was w pierwsz\u0105 podr\xf3\u017c po najbardziej u\u017cytecznych pluginach (oczywi\u015bcie to m\xf3j subiektywny wyb\xf3r), kt\xf3re powsta\u0142y dzi\u0119ki mo\u017cliwo\u015bciom, jakie daje Union. Opisz\u0119 co nieco ich funkcjonalno\u015bci, jak dzia\u0142aj\u0105 i sk\u0105d je mo\u017cna pobra\u0107. Nie przed\u0142u\u017caj\u0105c \u2014 zapraszam do lektury.","date":"2026-04-03T00:00:00.000Z","tags":[{"inline":true,"label":"Pluginy","permalink":"/newsy/tags/pluginy"},{"inline":true,"label":"Union","permalink":"/newsy/tags/union"},{"inline":true,"label":"Modyfikacje","permalink":"/newsy/tags/modyfikacje"},{"inline":true,"label":"Gothic","permalink":"/newsy/tags/gothic"}],"readingTime":6.45,"hasTruncateMarker":true,"authors":[{"name":"Bezimienny111","url":"https://www.youtube.com/@Bezimienny111","key":"Bezimienny111","page":null}],"frontMatter":{"slug":"pluginy-union","title":"Najbardziej cziter\u2026 tzn. u\u017cyteczne pluginy pod Uniona","authors":["Bezimienny111"],"tags":["Pluginy","Union","Modyfikacje","Gothic"],"date":"2026-04-03T00:00:00.000Z","hide_table_of_contents":true},"unlisted":false,"nextItem":{"title":"Spolszczenie modyfikacji Escape from Freedom (Ucieczka od Wolno\u015bci)","permalink":"/newsy/spolszczenie-escape-from-freedom"}},"content":"<img src=\\"/img/images/Pluginy.png\\" alt=\\"Najbardziej u\u017cyteczne pluginy pod Uniona\\" style={{width: \'100%\', borderRadius: \'10px\', marginBottom: \'1.5rem\'}} />\\r\\n\\r\\nDzi\u015b chcia\u0142bym zaprosi\u0107 Was w pierwsz\u0105 podr\xf3\u017c po najbardziej u\u017cytecznych pluginach (oczywi\u015bcie to m\xf3j subiektywny wyb\xf3r), kt\xf3re powsta\u0142y dzi\u0119ki mo\u017cliwo\u015bciom, jakie daje Union. Opisz\u0119 co nieco ich funkcjonalno\u015bci, jak dzia\u0142aj\u0105 i sk\u0105d je mo\u017cna pobra\u0107. Nie przed\u0142u\u017caj\u0105c \u2014 zapraszam do lektury.\\r\\n\\r\\n\x3c!-- truncate --\x3e\\r\\n\\r\\n**Opisane pluginy:**\\r\\n<div className=\\"plugin-badges\\">\\r\\n  <a href=\\"#1-zutilities\\"><span className=\\"badge-num\\">1</span> zUtilities</a>\\r\\n  <a href=\\"#2-zhackchest\\"><span className=\\"badge-num\\">2</span> zHackChest</a>\\r\\n  <a href=\\"#3-flyingcreaturesfix\\"><span className=\\"badge-num\\">3</span> FlyingCreaturesFix</a>\\r\\n  <a href=\\"#4-quickslots\\"><span className=\\"badge-num\\">4</span> QuickSlots</a>\\r\\n  <a href=\\"#5-snaplocator-tzw-pstrykacz\\"><span className=\\"badge-num\\">5</span> SnapLocator</a>\\r\\n  <a href=\\"#6-voblocator\\"><span className=\\"badge-num\\">6</span> VobLocator</a>\\r\\n  <a href=\\"#7-itemmap\\"><span className=\\"badge-num\\">7</span> ItemMap</a>\\r\\n  <a href=\\"#8-eksperymentalny-plugin-unionminimap-by-tieru\\"><span className=\\"badge-num\\">8</span> UnionMinimap</a>\\r\\n  <a href=\\"#9-autoquickloot\\"><span className=\\"badge-num\\">9</span> AutoQuickLoot</a>\\r\\n</div>\\r\\n\\r\\n## 1. zUtilities\\r\\n\\r\\nChyba najwa\u017cniejszy i najbardziej podstawowy plugin, kt\xf3ry powinien zainstalowa\u0107 ka\u017cdy gracz Gothica. Dlaczego tak uwa\u017cam? Poniewa\u017c jedn\u0105 z jego funkcji jest ulepszony szybki zapis, kt\xf3ry wykorzystuje 5 slot\xf3w. Dodatkowo posiada takie funkcje, jak wy\u015bwietlanie liczby HP, pokazywanie obra\u017ce\u0144, wy\u015bwietlanie ilo\u015bci posiadanych strza\u0142/be\u0142t\xf3w dla aktualnie za\u0142o\u017conej broni czy przyspieszenie czasu.\\r\\n\\r\\n<div className=\\"blog-note\\">\\r\\n<strong>\ud83d\udce5 \u0179r\xf3d\u0142o:</strong> Do pobrania ze <a href=\\"https://www.sefaris.eu/union/plugins\\">strony Sefaris</a>.\\r\\n</div>\\r\\n\\r\\n## 2. zHackChest\\r\\n\\r\\nPlugin dla os\xf3b zm\u0119czonych minigierk\u0105 lewo-prawo w trakcie otwierania zamk\xf3w. Wspomaga otwieranie zamk\xf3w poprzez dodanie mo\u017cliwo\u015bci szybkiego otwarcia za pomoc\u0105 si\u0142y, zr\u0119czno\u015bci lub many. Pozwala otworzy\u0107 zamek za pomoc\u0105 jednego klawisza, z wykorzystaniem atrybut\xf3w. W zale\u017cno\u015bci od wykorzystanego atrybutu gracz wykonuje inne animacje przy otwieraniu zamka.\\r\\n\\r\\n<div className=\\"blog-note\\">\\r\\n<strong>\ud83d\udce5 \u0179r\xf3d\u0142o:</strong> Najnowsza wersja testowa do pobrania z <a href=\\"https://discord.gg/9EVFJv5Uyf\\">Discorda Sefaris</a> w sekcji <em>Union-pluginy-beta</em>.\\r\\n</div>\\r\\n\\r\\n<div className=\\"screenshot-gallery\\">\\r\\n  <a href=\\"/img/images/Plugins_A/HC.png\\" target=\\"_blank\\"><img src=\\"/img/images/Plugins_A/HC.png\\" alt=\\"zHackChest \u2014 otwieranie zamk\xf3w\\" /></a>\\r\\n</div>\\r\\n\\r\\n## 3. FlyingCreaturesFix\\r\\n\\r\\nDu\u017co tu nie b\u0119d\u0119 opisywa\u0142, a przekopiuj\u0119 opis ze strony Sefaris, z kt\xf3rej mo\u017cna go pobra\u0107:\\r\\n\\r\\n<div className=\\"interview-qa\\">\\r\\n<div className=\\"interview-answer\\">\\r\\n<div className=\\"interview-person\\">Opis ze strony Sefaris</div>\\r\\n\\r\\nPlugin naprawia problemy z blokowaniem si\u0119 potwor\xf3w na kraw\u0119dziach oraz z lataj\u0105cymi potworami, kt\xf3re unosz\u0105 si\u0119 zbyt wysoko nad ziemi\u0105, przez co nie mo\u017cna ich uderzy\u0107 broni\u0105 bia\u0142\u0105.\\r\\n\\r\\n</div>\\r\\n</div>\\r\\n\\r\\n<div className=\\"blog-note\\">\\r\\n<strong>\ud83d\udce5 \u0179r\xf3d\u0142o:</strong> Do pobrania ze <a href=\\"https://www.sefaris.eu/union/plugins\\">strony Sefaris</a>.\\r\\n</div>\\r\\n\\r\\n## 4. QuickSlots\\r\\n\\r\\nPlugin dodaj\u0105cy pasek szybkiego dost\u0119pu znany z wielu gier RPG. Pozwol\u0119 tutaj si\u0119 pokusi\u0107 o skopiowanie opisu od autora pluginu \u2014 **fyryNy**:\\r\\n\\r\\n<div className=\\"interview-qa\\">\\r\\n<div className=\\"interview-answer\\">\\r\\n<div className=\\"interview-person\\">fyryNy</div>\\r\\n\\r\\nPasek szybkiego dost\u0119pu przedmiot\xf3w z opcj\u0105 slot\xf3w alternatywnych oraz mo\u017cliwo\u015bci\u0105 zapisywania preset\xf3w.\\r\\n\\r\\n**Funkcjonalno\u015bci:**\\r\\n- Mo\u017cliwo\u015b\u0107 dowolnego przypisywania przedmiot\xf3w/spelli pod klawisze 1\u20130, zamiast pod klawisze funkcyjne (F1\u2013F10 czy ile tam obs\u0142uguj\u0105 ruskie pluginy).\\r\\n- Mo\u017cliwo\u015b\u0107 przypisania \u0142\u0105cznie nawet 20 item\xf3w/spelli.\\r\\n- Mo\u017cliwo\u015b\u0107 zapisania 4 preset\xf3w (zapisuje przypisania item\xf3w na pasku, a tak\u017ce aktualnie wyekwipowane przedmioty).\\r\\n\\r\\n</div>\\r\\n</div>\\r\\n\\r\\n<div className=\\"blog-note\\">\\r\\n<strong>\ud83d\udce5 \u0179r\xf3d\u0142o:</strong> Najnowsza wersja testowa do pobrania z <a href=\\"https://discord.gg/9EVFJv5Uyf\\">Discorda Sefaris</a> w sekcji <em>Union-pluginy-beta</em>.\\r\\n</div>\\r\\n\\r\\n<div className=\\"screenshot-gallery\\">\\r\\n  <a href=\\"/img/images/Plugins_A/QS.png\\" target=\\"_blank\\"><img src=\\"/img/images/Plugins_A/QS.png\\" alt=\\"QuickSlots \u2014 pasek szybkiego dost\u0119pu\\" /></a>\\r\\n</div>\\r\\n\\r\\n## 5. SnapLocator, tzw. \u201ePstrykacz\\"\\r\\n\\r\\nJedn\u0105 z funkcji, kt\xf3ra jest bardzo cz\u0119sto spotykana w wielu grach RPG (i nie tylko) \u2014 r\xf3wnie\u017c nawet tych starszych \u2014 jest mo\u017cliwo\u015b\u0107 pod\u015bwietlania przedmiot\xf3w w okolicy gracza. SnapLocator pozwala w\u0142a\u015bnie na co\u015b takiego, w spos\xf3b, kt\xf3ry nie zaburza odczu\u0107 w trakcie rozgrywki. Zgodnie z opisem:\\r\\n\\r\\n<div className=\\"interview-qa\\">\\r\\n<div className=\\"interview-answer\\">\\r\\n<div className=\\"interview-person\\">Opis pluginu</div>\\r\\n\\r\\nPlugin nak\u0142ada efekty cz\u0105steczkowe na pobliskie przedmioty, kt\xf3re mo\u017cna podnie\u015b\u0107, dzi\u0119ki czemu mo\u017cna je \u0142atwiej zauwa\u017cy\u0107.\\r\\n\\r\\n</div>\\r\\n</div>\\r\\n\\r\\nA sk\u0105d nazwa \u201ePstrykacz\\"? W momencie u\u017cycia posta\u0107 wykonuje animacj\u0119 pstrykni\u0119cia palcami, a akcji tej towarzyszy odpowiedni odg\u0142os.\\r\\n\\r\\n<div className=\\"blog-note\\">\\r\\n<strong>\ud83d\ude04 Ciekawostka:</strong> Chodz\u0105 s\u0142uchy, \u017ce najtrudniejsz\u0105 cz\u0119\u015bci\u0105 prac nad pluginem by\u0142o uzyskanie idealnego odg\u0142osu pstrykni\u0119cia palcami przez autora pluginu <strong>fyryNy</strong> \u2014 oczywi\u015bcie to \u017cart. \ud83d\ude09\\r\\n</div>\\r\\n\\r\\n<div className=\\"blog-note\\">\\r\\n<strong>\ud83d\udce5 \u0179r\xf3d\u0142o:</strong> Najnowsza wersja testowa do pobrania z <a href=\\"https://discord.gg/9EVFJv5Uyf\\">Discorda Sefaris</a> w sekcji <em>Union-pluginy-beta</em>.\\r\\n</div>\\r\\n\\r\\n<div className=\\"screenshot-gallery\\">\\r\\n  <a href=\\"/img/images/Plugins_A/Snap.png\\" target=\\"_blank\\"><img src=\\"/img/images/Plugins_A/Snap.png\\" alt=\\"SnapLocator \u2014 pod\u015bwietlanie przedmiot\xf3w\\" /></a>\\r\\n</div>\\r\\n\\r\\n## 6. VobLocator\\r\\n\\r\\nAlternatywa, zdecydowanie bardziej inwazyjna dla odczu\u0107 w rozgrywce ni\u017c SnapLocator. Zale\u017cnie od wersji, w formie ikonek albo \u015bwiec\u0105cych punkt\xf3w, wskazuje w \u015bwiecie gry praktycznie wszystkie elementy \u2014 od item\xf3w, przez skrzynki i prze\u0142\u0105czniki, po NPC-\xf3w. Ma zdecydowanie wi\u0119cej funkcjonalno\u015bci, ale w opinii cz\u0119\u015bci graczy psuje odczucia w trakcie rozgrywki. Sam u\u017cywam go czasem w przypadku poszukiwania ukrytych prze\u0142\u0105cznik\xf3w.\\r\\n\\r\\n<div className=\\"blog-note\\">\\r\\n<strong>\u26a0\ufe0f Uwaga:</strong> \u201ePlugin zakazany regulaminem gry w Gothica w punkcie 404, ust\u0119pie 69 paragrafu 2147\\" \ud83d\ude43\\r\\n</div>\\r\\n\\r\\n<div className=\\"blog-note\\">\\r\\n<strong>\ud83d\udce5 \u0179r\xf3d\u0142o:</strong> Do pobrania ze <a href=\\"https://www.sefaris.eu/union/plugins\\">strony Sefaris</a>.\\r\\n</div>\\r\\n\\r\\n<div className=\\"screenshot-gallery\\">\\r\\n  <a href=\\"/img/images/Plugins_A/vob.png\\" target=\\"_blank\\"><img src=\\"/img/images/Plugins_A/vob.png\\" alt=\\"VobLocator \u2014 wskazywanie element\xf3w \u015bwiata\\" /></a>\\r\\n</div>\\r\\n\\r\\n## 7. ItemMap\\r\\n\\r\\nJeden z najwa\u017cniejszych plugin\xf3w dla graczy, kt\xf3rzy uwielbiaj\u0105 maksowa\u0107 gr\u0119. Po otworzeniu mapy wy\u015bwietla w formie punkt\xf3w przedmioty, NPC-\xf3w, skrzynki b\u0105d\u017a elementy interaktywne \u2014 zale\u017cnie od wybranego trybu. Dodatkowo pozwala na filtrowanie po nazwach b\u0105d\u017a instancjach. Brakuje Ci jednego szczawiu kr\xf3lewskiego? \u017baden problem. Znikn\u0105\u0142 Ci jaki\u015b NPC? Wpisz jego imi\u0119. W najnowszych wersjach mamy r\xf3wnie\u017c takie funkcje, jak przeszukiwanie ekwipunku NPC-\xf3w, przeszukiwanie zawarto\u015bci skrzynek czy mo\u017cliwo\u015b\u0107 u\u017cycia pluginu, nawet gdy gracz nie posiada mapy lokacji.\\r\\n\\r\\n<div className=\\"blog-note\\">\\r\\n<strong>\ud83d\udce5 \u0179r\xf3d\u0142o:</strong> Do pobrania ze <a href=\\"https://www.sefaris.eu/union/plugins\\">strony Sefaris</a>.\\r\\n</div>\\r\\n\\r\\n<div className=\\"screenshot-gallery\\">\\r\\n  <a href=\\"/img/images/Plugins_A/item1png.png\\" target=\\"_blank\\"><img src=\\"/img/images/Plugins_A/item1png.png\\" alt=\\"ItemMap \u2014 mapa przedmiot\xf3w 1\\" /></a>\\r\\n  <a href=\\"/img/images/Plugins_A/item2png.png\\" target=\\"_blank\\"><img src=\\"/img/images/Plugins_A/item2png.png\\" alt=\\"ItemMap \u2014 mapa przedmiot\xf3w 2\\" /></a>\\r\\n</div>\\r\\n\\r\\n## 8. Eksperymentalny plugin UnionMinimap by Tieru\\r\\n\\r\\nMinimapa \u2014 dla jednych nieod\u0142\u0105czny element gier RPG, dla innych \u015bmiertelny wr\xf3g immersyjno\u015bci. Ale tak, minimapa w Gothicu \u2014 nikt si\u0119 nie spodziewa\u0142, ale jest. Jakie ma funkcje? Pokazuje NPC-\xf3w, itemy, skrzynki w najbli\u017cszej okolicy. Ale nie tylko \u2014 ma r\xf3wnie\u017c mo\u017cliwo\u015b\u0107 wyszukania jakiego\u015b NPC w \u015bwiecie gry i wyznaczenia prostej linii do niego. O szczeg\xf3\u0142ach mo\u017cecie poczyta\u0107 pod poni\u017cszym linkiem.\\r\\n\\r\\n<div className=\\"blog-note\\">\\r\\n<strong>\u26a0\ufe0f Uwaga:</strong> Jest to bardzo eksperymentalny plugin i nie gwarantuj\u0119 dzia\u0142ania z ka\u017cdym modem. Sam zauwa\u017cy\u0142em, \u017ce na przyk\u0142ad w przypadku G1 dzia\u0142a mi tylko wersja 3.1.\\r\\n</div>\\r\\n\\r\\n<div className=\\"blog-note\\">\\r\\n<strong>\ud83d\udce5 \u0179r\xf3d\u0142o:</strong> Do pobrania z <a href=\\"https://github.com/TieruYT/UnionMinimap/releases\\">GitHuba autora</a>.\\r\\n</div>\\r\\n\\r\\n<div className=\\"screenshot-gallery\\">\\r\\n  <a href=\\"/img/images/Plugins_A/Minimap.png\\" target=\\"_blank\\"><img src=\\"/img/images/Plugins_A/Minimap.png\\" alt=\\"UnionMinimap \u2014 minimapa 1\\" /></a>\\r\\n  <a href=\\"/img/images/Plugins_A/minimap2.png\\" target=\\"_blank\\"><img src=\\"/img/images/Plugins_A/minimap2.png\\" alt=\\"UnionMinimap \u2014 minimapa 2\\" /></a>\\r\\n</div>\\r\\n\\r\\n## 9. AutoQuickLoot\\r\\n\\r\\nSzybkie zbieranie przedmiot\xf3w bez animacji podnoszenia \u2014 jeden z najbardziej u\u017cytecznych plugin\xf3w, kt\xf3ry zapewnia ogromn\u0105 oszcz\u0119dno\u015b\u0107 czasu. Dodatkowo wersja od **Hedina** posiada opcjonaln\u0105 funkcj\u0119 automatycznego zbierania przedmiot\xf3w le\u017c\u0105cych dooko\u0142a gracza, kt\xf3ra dzia\u0142a o wiele sprawniej od starego pluginu na ognika. Plugin oferuje r\xf3wnie\u017c konfiguracj\u0119 odleg\u0142o\u015bci, z jakiej ma automatycznie zbiera\u0107, a tak\u017ce mo\u017cliwo\u015b\u0107 wykluczenia z szybkiego podnoszenia przedmiot\xf3w zwi\u0105zanych z misjami, skrzynek czy przeszukiwania cia\u0142.\\r\\n\\r\\n<div className=\\"blog-note\\">\\r\\n<strong>\ud83d\udce5 \u0179r\xf3d\u0142o:</strong> Do pobrania ze <a href=\\"https://www.sefaris.eu/union/plugins\\">strony Sefaris</a>.\\r\\n</div>"},{"id":"spolszczenie-escape-from-freedom","metadata":{"permalink":"/newsy/spolszczenie-escape-from-freedom","source":"@site/newsy/2026-04-02-spolszczenie-escape-from-freedom.md","title":"Spolszczenie modyfikacji Escape from Freedom (Ucieczka od Wolno\u015bci)","description":"Zesp\xf3\u0142 Sefaris aktywnie pracuje nad spolszczeniem modyfikacji Escape from Freedom autorstwa u\u017cytkownika Scarecrow. Aktualnie prace nad spolszczeniem wesz\u0142y ju\u017c w faz\u0119 test\xf3w, tak wi\u0119c ju\u017c za nied\u0142ugi czas mo\u017cemy spodziewa\u0107 si\u0119 premiery.","date":"2026-04-02T00:00:00.000Z","tags":[{"inline":true,"label":"Modyfikacje","permalink":"/newsy/tags/modyfikacje"},{"inline":true,"label":"Addon","permalink":"/newsy/tags/addon"},{"inline":true,"label":"Gothic1","permalink":"/newsy/tags/gothic-1"},{"inline":true,"label":"Sefaris","permalink":"/newsy/tags/sefaris"},{"inline":true,"label":"Spolszczenie","permalink":"/newsy/tags/spolszczenie"}],"readingTime":2.47,"hasTruncateMarker":true,"authors":[{"name":"Bezimienny111","url":"https://www.youtube.com/@Bezimienny111","key":"Bezimienny111","page":null}],"frontMatter":{"slug":"spolszczenie-escape-from-freedom","title":"Spolszczenie modyfikacji Escape from Freedom (Ucieczka od Wolno\u015bci)","authors":["Bezimienny111"],"tags":["Modyfikacje","Addon","Gothic1","Sefaris","Spolszczenie"],"date":"2026-04-02T00:00:00.000Z","hide_table_of_contents":true,"draft":false},"unlisted":false,"prevItem":{"title":"Najbardziej cziter\u2026 tzn. u\u017cyteczne pluginy pod Uniona","permalink":"/newsy/pluginy-union"},"nextItem":{"title":"Wkr\xf3tce...","permalink":"/newsy/coming-soon"}},"content":"<img src=\\"/img/images/EFF/Spol.png\\" alt=\\"Spolszczenie Escape from Freedom\\" style={{width: \'100%\', borderRadius: \'10px\', marginBottom: \'1.5rem\'}} />\\r\\n\\r\\nZesp\xf3\u0142 **Sefaris** aktywnie pracuje nad spolszczeniem modyfikacji **Escape from Freedom** autorstwa u\u017cytkownika **Scarecrow**. Aktualnie prace nad spolszczeniem wesz\u0142y ju\u017c w faz\u0119 test\xf3w, tak wi\u0119c ju\u017c za nied\u0142ugi czas mo\u017cemy spodziewa\u0107 si\u0119 premiery.\\r\\n\\r\\n\x3c!-- truncate --\x3e\\r\\n\\r\\n## Czym jest mod?\\r\\n\\r\\nJest to addon rozszerzaj\u0105cy **Gothica 1**. Mod dodaje mo\u017cliwo\u015b\u0107 przej\u015bcia gry bez przynale\u017cno\u015bci do jednej z g\u0142\xf3wnych gildii. \u015acie\u017cka ta opowiada histori\u0119 znan\u0105 nam z wydarze\u0144 z Gothica 1 z ca\u0142kowicie innej, nowej perspektywy. G\u0142\xf3wnym elementem tej \u015bcie\u017cki jest spotkanie tajemniczej postaci, kt\xf3ra zg\u0142\u0119bia wiedz\u0119 Bractwa \u015ani\u0105cego. Dzi\u0119ki niej bohater stopniowo odkrywa kolejne sekrety Kolonii, poznaj\u0105c jej mniej oczywiste i bardziej intryguj\u0105ce oblicze.\\r\\n\\r\\nOczywi\u015bcie \u015bcie\u017cka ta nie jest ca\u0142kowicie oderwana od \u017cycia oboz\xf3w i w jej trakcie napotkamy wiele nawi\u0105za\u0144 do znanych nam gildii, jak i postaci. Ale to nie wszystko \u2014 gracze natrafi\u0105 na subtelne nawi\u0105zania do przysz\u0142ych wydarze\u0144 znanych z Gothic 2 i Gothic 3, co nadaje historii wi\u0119kszej g\u0142\u0119bi i sp\xf3jno\u015bci z uniwersum.\\r\\n\\r\\nOpr\xf3cz tego rozgrywk\u0119 urozmaicaj\u0105 r\xf3wnie\u017c dodatkowi minibossowie, kt\xf3rzy \u2014 zale\u017cnie od przygotowania gracza \u2014 mog\u0105 stanowi\u0107 do\u015b\u0107 powa\u017cne wyzwanie.\\r\\n\\r\\n## Opis modyfikacji od autora\\r\\n\\r\\nPoni\u017cszy opis pochodzi ze [strony modyfikacji](https://worldofplayers.ru/threads/43841/):\\r\\n\\r\\n<div className=\\"interview-qa\\">\\r\\n<div className=\\"interview-answer\\">\\r\\n<div className=\\"interview-person\\">Scarecrow</div>\\r\\n\\r\\n**Ucieczka od Wolno\u015bci** to modyfikacja do Gothic I, kt\xf3ra wprowadza now\u0105 lini\u0119 fabularn\u0105 osadzon\u0105 w realiach Kolonii Karnej. Mod rozwija wydarzenia znane z orygina\u0142u, ale prowadzi gracza w\u0142asn\u0105 \u015bcie\u017ck\u0105 \u2014 niezale\u017cn\u0105 od klasycznego podzia\u0142u na obozy i niezwi\u0105zan\u0105 bezpo\u015brednio z rozdzia\u0142ami gry. Jednocze\u015bnie zachowano mo\u017cliwo\u015b\u0107 przej\u015bcia gry w bardziej standardowy spos\xf3b. Cz\u0119\u015b\u0107 nowych zada\u0144 mo\u017ce wp\u0142ywa\u0107 na przebieg g\u0142\xf3wnej historii.\\r\\n\\r\\n**Co oferuje modyfikacja?**\\r\\n\\r\\n- ponad 120 nowych zada\u0144\\r\\n- now\u0105 \u015bcie\u017ck\u0119 fabularn\u0105\\r\\n- nowych bohater\xf3w niezale\u017cnych\\r\\n- nowe przedmioty, w tym bro\u0144 i pancerze\\r\\n- nowe umiej\u0119tno\u015bci i dodatkowe mo\u017cliwo\u015bci rozgrywki\\r\\n- kilka nowych lokacji\\r\\n- mo\u017cliwo\u015b\u0107 uko\u0144czenia gry tak\u017ce w klasyczny spos\xf3b\\r\\n\\r\\n</div>\\r\\n</div>\\r\\n\\r\\n## Screenshoty\\r\\n\\r\\n<div className=\\"screenshot-gallery\\">\\r\\n  <a href=\\"/img/images/EFF/image (1).webp\\" target=\\"_blank\\"><img src=\\"/img/images/EFF/image (1).webp\\" alt=\\"Screenshot 1\\" /></a>\\r\\n  <a href=\\"/img/images/EFF/image (2).webp\\" target=\\"_blank\\"><img src=\\"/img/images/EFF/image (2).webp\\" alt=\\"Screenshot 2\\" /></a>\\r\\n  <a href=\\"/img/images/EFF/image (3).webp\\" target=\\"_blank\\"><img src=\\"/img/images/EFF/image (3).webp\\" alt=\\"Screenshot 3\\" /></a>\\r\\n  <a href=\\"/img/images/EFF/image (4).webp\\" target=\\"_blank\\"><img src=\\"/img/images/EFF/image (4).webp\\" alt=\\"Screenshot 4\\" /></a>\\r\\n  <a href=\\"/img/images/EFF/image (5).webp\\" target=\\"_blank\\"><img src=\\"/img/images/EFF/image (5).webp\\" alt=\\"Screenshot 5\\" /></a>\\r\\n  <a href=\\"/img/images/EFF/image (6).webp\\" target=\\"_blank\\"><img src=\\"/img/images/EFF/image (6).webp\\" alt=\\"Screenshot 6\\" /></a>\\r\\n  <a href=\\"/img/images/EFF/image (7).webp\\" target=\\"_blank\\"><img src=\\"/img/images/EFF/image (7).webp\\" alt=\\"Screenshot 7\\" /></a>\\r\\n  <a href=\\"/img/images/EFF/image (15).webp\\" target=\\"_blank\\"><img src=\\"/img/images/EFF/image (15).webp\\" alt=\\"Screenshot 8\\" /></a>\\r\\n</div>"},{"id":"coming-soon","metadata":{"permalink":"/newsy/coming-soon","source":"@site/newsy/2026-03-25-coming-soon.md","title":"Wkr\xf3tce...","description":"Dzia\u0142 news\xf3w w budowie. Zapraszamy wkr\xf3tce!","date":"2026-03-25T00:00:00.000Z","tags":[{"inline":true,"label":"temp","permalink":"/newsy/tags/temp"}],"readingTime":0.03,"hasTruncateMarker":false,"authors":[{"name":"Bezimienny111","url":"https://www.youtube.com/@Bezimienny111","key":"Bezimienny111","page":null}],"frontMatter":{"slug":"coming-soon","title":"Wkr\xf3tce...","authors":["Bezimienny111"],"tags":["temp"]},"unlisted":false,"prevItem":{"title":"Spolszczenie modyfikacji Escape from Freedom (Ucieczka od Wolno\u015bci)","permalink":"/newsy/spolszczenie-escape-from-freedom"}},"content":"Dzia\u0142 news\xf3w w budowie. Zapraszamy wkr\xf3tce!"}]}}')}}]);